import { Frame } from "./profile";

// Known editor URI schemes. To add a new editor, submit a PR adding its scheme here.
const ALLOWED_SCHEMES = [
  "vscode://",
  "vscode-insiders://",
  "cursor://",
  "idea://",
  "goland://",
  "pycharm://",
  "webstorm://",
  "phpstorm://",
  "rubymine://",
  "clion://",
  "rider://",
  "fleet://",
  "zed://",
  "sublime://",
  "txmt://",
  "atom://",
];

/**
 * Build a full editor URI for a source location.
 * editorUri is a base like "vscode://file" or "cursor://file".
 * Result: "vscode://file/path/to/file.ts:42:5"
 */
export function formatEditorLink(editorUri: string, frame: Frame): string {
  if (!frame.file) return "";
  if (!ALLOWED_SCHEMES.some((scheme) => editorUri.startsWith(scheme)))
    return "";
  const base = editorUri.replace(/\/+$/, "");
  const path = toAbsPath(frame.file);
  let loc = `${base}${path}`;
  if (frame.line != null) {
    loc += `:${frame.line}`;
    if (frame.col != null) loc += `:${frame.col}`;
  }
  return loc;
}

/** Strip file:// or file:/// prefix to get an absolute filesystem path */
function toAbsPath(file: string): string {
  if (file.startsWith("file:///")) return file.slice(7);
  if (file.startsWith("file://")) return file.slice(6);
  return file;
}
